  ('bookkeeper-moex-00758', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '臺北市陳先生107年度的綜合所得淨額為新臺幣$500萬，另其當年度有香港的利息所得$120萬，並領到 受益人與要保人皆為自己的年金保險金$50萬，當年度未上市櫃股票交易所得$80萬，及當年度綜合所得 稅有申報減除$70萬的非現金捐贈金額。試問陳先生當年度的基本所得額為多少？', '["$620萬", "$690萬", "$740萬", "$770萬"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
